// Callback ilə asinxron nümunə
function fetchData(callback) {
  setTimeout(() => {
    const data = { id: 1, name: 'Ali' };
    callback(data);
  }, 1000);
}

function displayData(data) {
  console.log('Məlumat alındı: ', data.name);
}

fetchData(displayData); // 1 saniyə sonra: Məlumat alındı: Ali

// Promise nümunəsi
function fetchDataPromise() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const data = { id: 2, name: 'Veli' };
      resolve(data);
    }, 1000);
  });
}

fetchDataPromise()
  .then(data => console.log('Məlumat alındı: ', data.name))
  .catch(error => console.log('Xəta: ', error)); // 1 saniyə sonra: Məlumat alındı: Veli

// async/await nümunəsi
function fetchDataPromise() {
  return new Promise((resolve) => {
    setTimeout(() => {
      const data = { id: 3, name: 'Aysu' };
      resolve(data);
    }, 1000);
  });
}

async function getData() {
  const data = await fetchDataPromise();
  console.log('Məlumat alındı: ', data.name);
}

getData(); // 1 saniyə sonra: Məlumat alındı: Aysu

// Səhvə yol açan callback nümunəsi
function fetchData(callback) {
  setTimeout(() => {
    const data = null;
    callback(data);
  }, 1000);
}

fetchData(data => console.log(data.name)); // TypeError: Cannot read property 'name' of null

// Düzgün yol (xəta idarəetmə ilə)
function fetchDataSafe(callback) {
  setTimeout(() => {
    const data = null;
    if (data) {
      callback(null, data);
    } else {
      callback('Məlumat yoxdur');
    }
  }, 1000);
}

fetchDataSafe((error, data) => {
  if (error) {
    console.log('Xəta: ', error);
  } else {
    console.log('Məlumat: ', data.name);
  }
}); // Xəta: Məlumat yoxdur

// Promise ilə xəta idarəetmə
function fetchDataWithError() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      reject('Məlumat alınmadı');
    }, 1000);
  });
}

fetchDataWithError()
  .then(data => console.log(data))
  .catch(error => console.log('Xəta: ', error)); // Xəta: Məlumat alınmadı

// async/await ilə xəta idarəetmə
async function getDataSafe() {
  try {
    const data = await fetchDataWithError();
    console.log(data);
  } catch (error) {
    console.log('Xəta: ', error);
  }
}

getDataSafe(); // Xəta: Məlumat alınmadı

