// Promise example
function fetchDataPromise() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const data = { id: 2, name: 'Veli' };
      resolve(data);
    }, 1000);
  });
}

fetchDataPromise()
  .then(data => console.log('Data received: ', data.name))
