// async/await example
function fetchDataPromise() {
  return new Promise((resolve) => {
    setTimeout(() => {
      const data = { id: 3, name: 'Aysu' };
      resolve(data);
    }, 1000);
  });
}

async function getData() {
  const data = await fetchDataPromise();
  console.log('Data received: ', data.name);
}

getData(); // After 1 second: Data received: Aysu

// Error-prone callback example
function fetchData(callback) {
  setTimeout(() => {
    const data = null;
    callback(data);
  }, 1000);
}

fetchData(data => console.log(data.name)); // TypeError: Cannot read property 'name' of null

// Correct approach (with error handling)
function fetchDataSafe(callback) {
  setTimeout(() => {
    const data = null;
    if (data) {
      callback(null, data);
    } else {
      callback('No data available');
    }
  }, 1000);
}

fetchDataSafe((error, data) => {
  if (error) {
    console.log('Error: ', error);
  } else {
    console.log('Data: ', data.name);
  }
}); // Error: No data available

// Error handling with Promise
function fetchDataWithError() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      reject('Data fetch failed');
    }, 1000);
  });
}

fetchDataWithError()
  .then(data => console.log(data))
  .catch(error => console.log('Error: ', error)); // Error: Data fetch failed

// Error handling with async/await
async function getDataSafe() {
  try {
    const data = await fetchDataWithError();
    console.log(data);
  } catch (error) {
    console.log('Error: ', error);
  }
}

getDataSafe(); // Error: Data fetch failed

